import { useLocation, useNavigate } from 'react-router-dom';
import './Batalla.css';
import { useState, useEffect } from 'react';

type CardShape = {
  idCard: number;
  name: string;
  tipo?: string;
  attack?: number;
  defense?: number;
  lifePoints?: number;
  description?: string;
  pictureUrl?: string;
};

export default function Batalla() {
  const { state } = useLocation();
  const navigate = useNavigate();
  const cards: CardShape[] = state?.cards ?? [];

  if (cards.length !== 2) {
    return (
      <div className="batalla-page">
        <h2>Batalla</h2>
        <p>No hay dos cartas seleccionadas.</p>
        <button onClick={() => navigate(-1)} className="btn-volver">Volver</button>
      </div>
    );
  }

  const [cardA, setCardA] = useState<CardShape>(cards[0]);
  const [cardB, setCardB] = useState<CardShape>(cards[1]);

  const [lifeA, setLifeA] = useState<number>(cards[0]?.lifePoints ?? 100);
  const [lifeB, setLifeB] = useState<number>(cards[1]?.lifePoints ?? 100);
  const [companion, setCompanion] = useState<any | null>(null);
  const [companionExtraTurn, setCompanionExtraTurn] = useState<boolean>(false);
  const [winner, setWinner] = useState<string | null>(null);
  const [turn, setTurn] = useState<number>(0); // 0 = A's turn, 1 = B's turn

  useEffect(() => {
    if (lifeA <= 0) setWinner(cardB.name);
    else if (lifeB <= 0) setWinner(cardA.name);
    else setWinner(null);
  }, [lifeA, lifeB]);

  // aplicar cambios desde Dragon (localStorage)
  useEffect(() => {
    try {
      const raw = localStorage.getItem('battle-updated');
      if (raw) {
        const parsed = JSON.parse(raw);
        if (parsed.cards && parsed.cards.length >= 2) {
          setCardA(parsed.cards[0]);
          setCardB(parsed.cards[1]);
          setLifeA(parsed.cards[0].lifePoints ?? (parsed.cards[0].lifePoints ?? 100));
          setLifeB(parsed.cards[1].lifePoints ?? (parsed.cards[1].lifePoints ?? 100));
        }
        if (parsed.companion) {
          setCompanion(parsed.companion);
          // si viene metadata para turno extra, activarlo y darle el turno al dueño
          const hasExtra = parsed.companion.extraTurnForId || localStorage.getItem('battle-extra-turn');
          if (hasExtra) {
            setCompanionExtraTurn(true);
            setTurn(parsed.companion.attachToIndex ?? 0);
          }
        }
        localStorage.removeItem('battle-updated');
      }
    } catch (e) {
      // ignore
    }
    // limpiar llave extra-turn (la usamos para activar la lógica arriba)
    try { localStorage.removeItem('battle-extra-turn'); } catch {}
  }, []);

  const companionAttack = () => {
    if (!companion) return;
    const atk = companion.card?.attack ?? 0;
    const owner = companion.attachToIndex ?? 0;
    if (owner === 0) {
      setLifeB((prev) => Math.max(0, prev - atk));
      setTurn(1);
    } else {
      setLifeA((prev) => Math.max(0, prev - atk));
      setTurn(0);
    }
    setCompanionExtraTurn(false);
    try { localStorage.removeItem('battle-extra-turn'); } catch {}
  };

  const dañoCritico = () => {
    if (winner) return;
    if (turn === 0) {
      const damage = (cardA.attack ?? 50);
      setLifeB((prev) => Math.max(0, prev - damage));
      setTurn(1);
    } else {
      const damage = (cardB.attack ?? 50);
      setLifeA((prev) => Math.max(0, prev - damage));
      setTurn(0);
    }
  };

  const dañoNormal = () => {
    if (winner) return;
    if (turn === 0) {
      const damage = (cardA.attack ?? 50);
      setLifeB((prev) => Math.max(0, prev - damage));
      setTurn(1);
    } else {
      const damage = (cardB.attack ?? 50);
      setLifeA((prev) => Math.max(0, prev - damage));
      setTurn(0);
    }
  };

  return (
    <div className="batalla-page">
      <button className="dragon-button" onClick={() => navigate('/dragon', { state: { cards: [cardA, cardB], turn } })}>
        <img src="data:image/jpeg;base64," alt="Bolas del dragon" />
        bolas del dragon
      </button>
      <h2> {cardA.name} VS {cardB.name}</h2>
      <div className="turn-indicator">Turno: <strong>{turn === 0 ? cardA.name : cardB.name}</strong>
        <br />
        <br />
        <center>
          <img src="https://i.pinimg.com/736x/e5/52/34/e5523410c9e108b7d5f063bb0403635a.jpg" width={100} height={100} alt="" className='logo' />
        </center>
      </div>

      <div className="batalla-grid">
        <div className={`batalla-card ${turn === 0 ? 'active' : ''}`}>
          <img src={cardA.pictureUrl} alt={cardA.name} />
          <h3>{cardA.name}</h3>
          <p>Ataque: {cardA.attack}</p>
          <p>Defensa: {cardA.defense}</p>
          <p>Vida: <strong>{lifeA}</strong></p>

          {companion && companion.attachToIndex === 0 && (
            <div className="companion-card">
              <img src={"data:image/jpeg;base64,"} alt={companion.card.name} />
              <div>{companion.card.name}</div>
            </div>
          )}
        </div>

        <div className="batalla-vs">VS</div>

        <div className={`batalla-card ${turn === 1 ? 'active' : ''}`}>
          <img src={cardB.pictureUrl} alt={cardB.name} />
          <h3>{cardB.name}</h3>
          <p>Ataque: {cardB.attack}</p>
          <p>Defensa: {cardB.defense}</p>
          <p>Vida: <strong>{lifeB}</strong></p>

          {companion && companion.attachToIndex === 1 && (
            <div className="companion-card">
              <img src={"data:image/jpeg;base64,"} alt={companion.card.name} />
              <div>{companion.card.name}</div>
            </div>
          )}
        </div>
      </div>

      <div className="batalla-actions" style={{ marginTop: 20, display: 'flex', gap: 12, justifyContent: 'center' }}>
        {companion && companionExtraTurn && companion.attachToIndex === turn && (
          <button className="btn-normal" onClick={companionAttack} disabled={!!winner}>
            ATACAR CON COMPAÑERO
            <br />
            <center>
              <img src={"data:image/jpeg;base64,"} border-radius="50%" alt={companion.card.name} width={100} height={100} className='companion-attack' />
            </center>
          </button>
        )}
        <button className="btn-critico" onClick={dañoCritico} disabled={!!winner}>
          KAMEKAMEJA

          <br />

          <center>
            <img src="https://i.pinimg.com/webp85/736x/a8/b9/e5/a8b9e5f88149db0960c6d7f3c604dd98.webp" width={100} height={100} className="kamekameja" />
          </center>

        </button>
        <button className="btn-normal" onClick={dañoNormal} disabled={!!winner}>
          PUÑO NORMAL

          <br />
          <center>
            <img src="https://i.pinimg.com/736x/c6/49/58/c64958caf9a912ad9e1a6af7a3a8e642.jpg" width={100} height={100} className='puño' />
          </center>
        </button>
      </div>

      {winner && <div style={{ marginTop: 18, fontWeight: 800, color: '#eeff00' }}>Ganador: {winner}</div>}

      <div style={{ marginTop: 20 }}>
        <button className="btn-volver" onClick={() => navigate(-1)}>Volver
          <br />
          <center>
            <img src="https://i.pinimg.com/736x/8e/8b/8f/8e8b8fea6c962ebffaa411e5ba947ea8.jpg" width={20} height={20} className='atras' />
          </center>
        </button>
      </div>
    </div>
  );
}
